import { Fragment } from 'react';

import type { SeriesActions } from '../../../../types/series-actions-template.js';
import { TooltipItem } from '../../../../types/tooltip.js';
import { ChartSeriesAction } from '../../../series-action/ChartSeriesAction.js';
import { useSeriesActions } from '../../../series-action/ChartSeriesActionContext.js';

export function findSeriesActions<T>(
  series: T[],
  getId: (series: T) => string,
  tooltipItem: TooltipItem,
) {
  return series.find((tooltipSeries) =>
    tooltipItem.id.includes(getId(tooltipSeries)),
  );
}

/**
 * Return the series action template with the original series entity
 * @param series -
 * @param getId -
 */
export function useTooltipSeriesActions<T>(
  series: T[],
  getId: (series: T) => string,
  ...rest: unknown[]
): SeriesActions<TooltipItem> {
  const { chartSeriesActions } = useSeriesActions();

  return (selectedSeries?: TooltipItem) => {
    if (selectedSeries === undefined) {
      return undefined;
    }

    const actionSeries = findSeriesActions(series, getId, selectedSeries);

    if (actionSeries) {
      const actions = chartSeriesActions?.(actionSeries, ...rest);

      if (actions) {
        if (
          actions instanceof Promise ||
          actions.type === ChartSeriesAction ||
          actions.type === Fragment
        ) {
          return actions;
        } else {
          throw new Error('Invalid type passed for ChartSeriesActions!');
        }
      }
    }
  };
}
